#include "interface.h"

uint64_t asof_join_sum(
    const std::vector<uint32_t>& dim_ts,
    const std::vector<uint32_t>& dim_values,
    const std::vector<uint32_t>& probe_ts,
    const std::vector<uint32_t>& probe_weights,
    int iters) {
  const std::size_t n = probe_ts.size();
  uint64_t sum = 0;
  std::size_t dim_idx = 0;
  std::size_t best_idx = 0;
  for (std::size_t i = 0; i < n; ++i) {
    while (dim_idx < dim_ts.size() && dim_ts[dim_idx] <= probe_ts[i]) {
      best_idx = dim_idx;
      ++dim_idx;
    }
    sum += static_cast<uint64_t>(dim_values[best_idx]) * static_cast<uint64_t>(probe_weights[i]);
  }
  return sum * static_cast<uint64_t>(iters);
}
